def cheapest_price_k_stops(n, flights, src, dst, K):
    INF = 10**15
    dist = [INF] * n
    dist[src] = 0
    for _ in range(K + 1):
        new = dist[:]
        for u, v, w in flights:
            if dist[u] + w < new[v]:
                new[v] = dist[u] + w
        dist = new
    return -1 if dist[dst] >= INF else dist[dst]

